import{_ as e,o as t,c as s,a as o}from"./chunks/plugin-vue_export-helper.CrIAyUQY.js";const u=JSON.parse('{"title":"VPN","description":"","frontmatter":{"title":"VPN","date":"2024-10-02T00:00:00.000Z"},"headers":[],"relativePath":"posts/2024-10-02-vpn.md","filePath":"posts/2024-10-02-vpn.md"}'),r={name:"posts/2024-10-02-vpn.md"};function a(_,p,n,c,d,i){return t(),s("div",null,[...p[0]||(p[0]=[o("<p>Все знают это слово. Именно поэтому за VPN сейчас выдают не VPN, а обычный прокси-сервер.</p><p>VPN - это когда ваш компьютер становится полноценным участником локальной сети.</p><p>Настроить реальный честный VPN очень сложно и может занять неделю у хорошего специалиста.</p><p>Настроить прокси в Нидерландах может любая домохозяйка освоившая командную строку.</p><p>Шаг 1 Покупаем сервер в другой стране.</p><p>Это стоит 300 р в месяц в hexcore, например.</p><p>Шаг 2 Устанавливаем любую ОС где есть ssh.</p><p>FreeBSD, Ubuntu</p><p>Шаг 3</p><p>Запускаем команду</p><p><code>ssh -D 127.0.0.1:3000 user@your.ip.add.ress</code></p><p>Теперь все запросы которые вы будете направлять на 3000 порт локальной системы, будут отправляться через туннель в другой стране.</p><p>Можно настроить SOCKS-5 прокси на этот адрес (127.0.0.1:3000) в браузере или использовать командную строку</p><p><code>curl -x socks5://127.0.0.1:3000 https://alterfo.github.io</code></p>",14)])])}const P=e(r,[["render",a]]);export{u as __pageData,P as default};
